xfa.event.change = validateUserInput(xfa.event.change, "0123456789");

function validateUserInput(enteredText, validChars){
	enteredText = String(enteredText);
	var numbers = String(validChars);
	var correctedText = "";
	var size = enteredText.length;

	for(var i = 0; i < size; i++){
		var ch = enteredText.charAt(i);
		if (numbers.indexOf(ch) != -1){
			correctedText += ch;
		}
	}
	return correctedText;		
}

