calculate.script:
if (PERIODFROM.access == "open"){
	if (PERIODFROM.rawValue != null && PERIODFROM.rawValue != "" && String(PERIODFROM.rawValue).length == 10 ){ //Adds date to DATE TO only if date has been entered in DATE FROM
		PERIODTO.rawValue = AddDays(PERIODFROM, Page1.FIELD20.rawValue);
	}
	else {
		PERIODTO.rawValue = "";
	}	
}

function AddDays( dateObj, daysOffset ) {
	// dateObj's format: YYYYMMDD
	//                   01234567
	var oldDateValue = dateObj.formattedValue;
	var year = oldDateValue.substr(0,4);
	var month = oldDateValue.substr(4,2) - 1;
	var day = oldDateValue.substr(6,2);
	var oldDate = new Date( year, month, day, 0, 0, 0, 0);
	var newDate = new Date(oldDate);
	newDate.setMilliseconds(daysOffset * 86400000);
	var month = newDate.getMonth() + 1;
	if( month < 10 ) {
		month = "0" + month;
	}	
	var monthDay = newDate.getDate();	
	if ( monthDay < 10 ) {
	  monthDay = "0" + monthDay;
	}
	// YYYYMMDD		
	return String(newDate.getFullYear()) + String(month) + String(monthDay);
}

