if ( !FIELD7.isNull && FIELD7.rawValue != '' )
{
   if ( this.rawValue < FIELD7.rawValue )
   {
      app.alert( "Return Date must occur after Departure date." );
      this.rawValue = '';
   }
}

if ( !FIELD3.isNull && FIELD3.rawValue != '' )
{
   if ( this.rawValue < FIELD3.rawValue )
   {
      app.alert( "Date must occur after from date." );
      this.rawValue = '';
   }
}

if ( !FIELD4.isNull && FIELD4.rawValue != '' )
{
   if ( this.rawValue > FIELD4.rawValue )
   {
      app.alert( "Date must occur before to date." );
      this.rawValue = '';
   }
}

if (this.access == "open"){
	scoFunctions.unlockSignature(NAME,SSN,POPUP2,FIELD5,ADDRESS,ORDINARY,TDY,EMERGEN,OTHER,ORGAN,ACCRUED,REQUESTED,PERIODFROM,Signature_BUTTON1);
}

//xfa.event.change = validateUserInput(xfa.event.change, "0123456789");

if (xfa.event.prevText != xfa.event.newText){ //Eliminates error generated if same date is selected after clearing data in Section 9.b Requested
	if (REQUESTED.rawValue == null || REQUESTED.rawValue == 0){ //Checks to see if Section 9.b has data or not
		xfa.host.messageBox("Blocks 9a and 9b must be completed first before Block 10a.");
		xfa.event.change = "";
		PERIODTO.rawValue = "";
	}
}

if (this.access == "open"){
	scoFunctions.unlockSignature(NAME,SSN,POPUP2,FIELD5,ADDRESS,ORDINARY,TDY,EMERGEN,OTHER,ORGAN,ACCRUED,REQUESTED,PERIODFROM,Signature_BUTTON1);
}

