variables.script:
function unlockSignature(Name,SSN,Rank,Date,Address,Ordinary,Emergency,Permissive,Other,Origin,Accrued,Requested,From,Requestor_Signature){
	if (Name.rawValue != null && SSN.rawValue != "" && Rank.rawValue != null
	   && Date.rawValue != null && Address.rawValue != null
	   && (Ordinary.rawValue == 2 || Emergency.rawValue == 3 || Permissive.rawValue == 4 || Other.rawValue == 5)
	   && Origin.rawValue != null && Accrued.rawValue != null && Requested.rawValue != null
	   && From.rawValue != null){
	   Requestor_Signature.access = "open";
	}
	else {
		Requestor_Signature.access = "protected";
	}
}

function unlockSignature7(Name,SSN,Rank,Date,Address){
	if (Name.rawValue != null && SSN.rawValue != null && Rank.rawValue != null
	   && Date.rawValue != null){
	   Address.access = "open";
	}
	else {
		Address.access = "protected";
	}
}

function unlockSignature12(Name,SSN,Rank){
	if (Name.rawValue != 0 && SSN.rawValue != 0){
	    Rank.access = "open";
	}
	else {
		Rank.access = "protected";
	}
}

event.script:
app.runtimeHighlight = false;
xfa.host.setFocus(xfa.form.form1.Page1.CNTRLNO);

var getSigField = event.target.getField("form1[0].Page1[0].Signature_BUTTON1[0]");
var oState = getSigField.signatureValidate();

if (oState == 0){
	if (Page1.NAME.rawValue != null && Page1.SSN.rawValue != null && Page1.POPUP2.rawValue != null && Page1.FIELD5.rawValue != null && Page1.ADDRESS.rawValue != null && Page1.ORDINARY.rawValue != null
	&& Page1.TDY.rawValue != null && Page1.EMERGEN.rawValue != null && Page1.OTHER.rawValue != null && Page1.ORGAN.rawValue != null && Page1.ACCRUED.rawValue != null && Page1.REQUESTED.rawValue != null
	&& Page1.PERIODFROM.rawValue != null) {
		Page1.Signature_BUTTON1.access = "open";
	}
	else {
		Page1.Signature_BUTTON1.access = "protected";
	}
}

var getSigField1 = event.target.getField("form1[0].Page1[0].Signature_BUTTON1[0]");
var oState1 = getSigField1.signatureValidate();
if (oState1 == 0){
	if (Page1.ORDINARY.rawValue == 2){
		Page1.POPUP3.presence = "visible";
		Page1.POPUP4.presence = "invisible";
		Page1.POPUP6.presence = "invisible";
		Page1.POPUP5.presence = "invisible";
	}
	else if (Page1.EMERGEN.rawValue == 3){
		Page1.POPUP3.presence = "invisible";
		Page1.POPUP4.presence = "visible";
		Page1.POPUP6.presence = "invisible";
		Page1.POPUP5.presence = "invisible";
	}
	else if (Page1.EMERGEN.rawValue == 4){
		Page1.POPUP3.presence = "invisible";
		Page1.POPUP4.presence = "invisible";
		Page1.POPUP6.presence = "visible";
		Page1.POPUP5.presence = "invisible";
	}
	else if (Page1.EMERGEN.rawValue == 5){
		Page1.POPUP3.presence = "invisible";
		Page1.POPUP4.presence = "invisible";
		Page1.POPUP6.presence = "invisible";
		Page1.POPUP5.presence = "visible";
	}
	else {
		Page1.POPUP3.presence = "invisible";
		Page1.POPUP4.presence = "invisible";
		Page1.POPUP6.presence = "invisible";
		Page1.POPUP5.presence = "invisible";
	}	
}
